package com.example.demoapi.controller;

import lombok.extern.slf4j.Slf4j;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/v1/demo")
@Slf4j // Lombok annotation to automatically create an SLF4J logger named 'log'
public class DemoController {

    @GetMapping("/hello/{name}")
    public ResponseEntity<String> sayHello(@PathVariable String name) {
        log.info("Received GET request for /api/v1/demo/hello/{} from client.", name);

        // Simulate some business logic processing
        try {
            log.debug("Processing 'hello' operation for name: {}.", name);
            String message = "Hello, " + name + "! Welcome to the Demo API!";
            log.info("Successfully processed 'hello' operation for name: {}. Responding with: {}", name, message);
            return ResponseEntity.ok(message);
        } catch (Exception e) {
            log.error("Error occurred while processing 'hello' operation for name: {}.", name, e);
            return ResponseEntity.internalServerError().body("An internal error occurred.");
        }
    }

    @GetMapping("/status")
    public ResponseEntity<String> getStatus() {
        log.debug("Received GET request for /api/v1/demo/status. Checking application health.");
        String statusMessage = "Demo API Service is running smoothly!";
        log.info("Application status checked successfully. Status: {}", statusMessage);
        return ResponseEntity.ok(statusMessage);
    }
}